sealed class AppException implements Exception {
  final String message;
  const AppException(this.message);
}

class NetworkException extends AppException {
  const NetworkException(super.message);
}

class UnauthorizedException extends AppException {
  const UnauthorizedException(super.message);
}

class ServerException extends AppException {
  const ServerException(super.message);
}

class ParsingException extends AppException {
  const ParsingException(super.message);
}

class TimeoutException extends AppException {
  const TimeoutException(super.message);
}

class UnknownException extends AppException {
  const UnknownException(super.message);
}

sealed class Failure {
  final String message;
  const Failure(this.message);
}

class NetworkFailure extends Failure {
  const NetworkFailure(super.message);
}

class UnauthorizedFailure extends Failure {
  const UnauthorizedFailure(super.message);
}

class ServerFailure extends Failure {
  const ServerFailure(super.message);
}

class UnknownFailure extends Failure {
  const UnknownFailure(super.message);
}

class TimeoutFailure extends Failure {
  const TimeoutFailure(super.message);
}

import 'exception.dart';
import 'failure.dart';

Failure mapException(AppException e) {

  if (e is NetworkException) {
    return NetworkFailure(e.message);
  }

  if (e is UnauthorizedException) {
    return UnauthorizedFailure(e.message);
  }

  if (e is TimeoutException) {
    return TimeoutFailure(e.message);
  }

  if (e is ServerException) {
    return ServerFailure(e.message);
  }

  return UnknownFailure(e.message);
}

import 'dart:convert';
import 'dart:io';
import 'package:http/http.dart' as http;

import '../errors/exception.dart';
import 'secret/token_storage.dart';

class ApiClient {
  final http.Client client;
  final TokenStorage tokenStorage;
  final String baseUrl;

  ApiClient({
    required this.client,
    required this.tokenStorage,
    required this.baseUrl,
  });

  static const _timeout = Duration(seconds: 20);

  /*
  --------------------------
  Base Request
  --------------------------
   */

  Future<dynamic> _request({
    required String method,
    required String path,
    Map<String, dynamic>? query,
    Map<String, String>? headers,
    dynamic body,
  }) async {
    final token = await tokenStorage.getAccessToken();

    final uri = Uri.parse("$baseUrl$path").replace(queryParameters: query);

    final requestHeaders = {
      "Content-Type": "application/json",
      if (token != null) "Authorization": "Bearer $token",
      ...?headers,
    };

    _logRequest(method, uri, body);

    try {
      final response = await _sendRequest(
        method,
        uri,
        requestHeaders,
        body,
      ).timeout(_timeout);

      _logResponse(response);

      return _handleResponse(
        method: method,
        path: path,
        response: response,
        query: query,
        body: body,
      );
    } on SocketException {
      throw const NetworkException("No internet connection");
    }
  }

  /*
  --------------------------
  Raw HTTP sender
  --------------------------
   */

  Future<http.Response> _sendRequest(
    String method,
    Uri uri,
    Map<String, String> headers,
    dynamic body,
  ) {
    switch (method) {
      case "GET":
        return client.get(uri, headers: headers);

      case "POST":
        return client.post(
          uri,
          headers: headers,
          body: body != null ? jsonEncode(body) : null,
        );

      case "PUT":
        return client.put(
          uri,
          headers: headers,
          body: body != null ? jsonEncode(body) : null,
        );

      case "PATCH":
        return client.patch(
          uri,
          headers: headers,
          body: body != null ? jsonEncode(body) : null,
        );

      case "DELETE":
        return client.delete(uri, headers: headers);

      default:
        throw UnsupportedError("Unsupported method $method");
    }
  }

  /*
  --------------------------
  CRUD METHODS
  --------------------------
   */

  Future<dynamic> get(
    String path, {
    Map<String, dynamic>? query,
  }) {
    return _request(
      method: "GET",
      path: path,
      query: query,
    );
  }

  Future<dynamic> post(
    String path, {
    dynamic body,
    Map<String, dynamic>? query,
  }) {
    return _request(
      method: "POST",
      path: path,
      body: body,
      query: query,
    );
  }

  Future<dynamic> put(
    String path, {
    dynamic body,
  }) {
    return _request(
      method: "PUT",
      path: path,
      body: body,
    );
  }

  Future<dynamic> patch(
    String path, {
    dynamic body,
  }) {
    return _request(
      method: "PATCH",
      path: path,
      body: body,
    );
  }

  Future<dynamic> delete(String path) {
    return _request(
      method: "DELETE",
      path: path,
    );
  }

  /*
  --------------------------
  FILE UPLOAD
  --------------------------
   */

  Future<dynamic> uploadFile(
    String path, {
    required String filePath,
    String field = "file",
    Map<String, String>? fields,
  }) async {
    final token = await tokenStorage.getAccessToken();

    final uri = Uri.parse("$baseUrl$path");

    final request = http.MultipartRequest("POST", uri);

    request.headers.addAll({
      if (token != null) "Authorization": "Bearer $token",
    });

    if (fields != null) {
      request.fields.addAll(fields);
    }

    request.files.add(
      await http.MultipartFile.fromPath(field, filePath),
    );

    _logRequest("UPLOAD", uri, fields);

    final streamed = await request.send();

    final response = await http.Response.fromStream(streamed);

    _logResponse(response);

    return _handleResponse(
      method: "POST",
      path: path,
      response: response,
    );
  }

  /*
  --------------------------
  RESPONSE HANDLER
  --------------------------
   */

  Future<dynamic> _handleResponse({
    required String method,
    required String path,
    required http.Response response,
    Map<String, dynamic>? query,
    dynamic body,
  }) async {
    switch (response.statusCode) {
      case 200:
      case 201:
        return jsonDecode(response.body);

      case 204:
        return true;

      case 401:
        return _refreshAndRetry(
          method: method,
          path: path,
          query: query,
          body: body,
        );

      case 500:
        throw const ServerException("Server error");

      default:
        throw ServerException(
          "Error ${response.statusCode}",
        );
    }
  }

  /*
  --------------------------
  TOKEN REFRESH
  --------------------------
   */

  Future<dynamic> _refreshAndRetry({
    required String method,
    required String path,
    Map<String, dynamic>? query,
    dynamic body,
  }) async {
    final refreshToken = await tokenStorage.getRefreshToken();

    if (refreshToken == null) {
      throw const UnauthorizedException("Session expired");
    }

    final response = await client.post(
      Uri.parse("$baseUrl/refresh"),
      headers: {"Content-Type": "application/json"},
      body: jsonEncode({
        "refresh_token": refreshToken,
      }),
    );

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);

      await tokenStorage.saveAccessToken(
        data["access_token"],
      );

      return _request(
        method: method,
        path: path,
        query: query,
        body: body,
      );
    }

    throw const UnauthorizedException("Login required");
  }

  /*
  --------------------------
  LOGGER
  --------------------------
   */

  void _logRequest(
    String method,
    Uri uri,
    dynamic body,
  ) {
    print("┌────────────────────────────────");
    print("│ HTTP Request");
    print("│ $method $uri");
    if (body != null) print("│ Body: $body");
    print("└────────────────────────────────");
  }

  void _logResponse(http.Response response) {
    print("┌────────────────────────────────");
    print("│ HTTP Response");
    print("│ Status: ${response.statusCode}");
    print("│ Body: ${response.body}");
    print("└────────────────────────────────");
  }
}

import 'package:dartz/dartz.dart';
import '../../errors/exception.dart';
import '../../errors/failure.dart';

Future<Either<Failure, T>> safeApiCall<T>(
  Future<T> Function() request,
) async {
  try {
    final result = await request();
    return Right(result);
  } on NetworkException catch (e) {
    return Left(NetworkFailure(e.message));
  } on UnauthorizedException catch (e) {
    return Left(UnauthorizedFailure(e.message));
  } on ServerException catch (e) {
    return Left(ServerFailure(e.message));
  } catch (e) {
    return Left(UnknownFailure(e.toString()));
  }
}

import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class TokenStorage {
  final _storage = const FlutterSecureStorage();

  Future<void> saveAccessToken(String token) {
    return _storage.write(key: "access_token", value: token);
  }

  Future<void> saveRefreshToken(String token) {
    return _storage.write(key: "refresh_token", value: token);
  }

  Future<String?> getAccessToken() {
    return _storage.read(key: "access_token");
  }

  Future<String?> getRefreshToken() {
    return _storage.read(key: "refresh_token");
  }

  Future<void> clear() async {
    await _storage.deleteAll();
  }
}
